    return top;
  }
}

function lastStoneWeight(stones) {
  const h = new MinHeap();
  for (const s of stones) h.push(-s);
  while (h.size() > 1) {
    const a = -h.pop();
    const b = -h.pop();
    if (a !== b) h.push(-(a - b));
  }
  return h.size() > 0 ? -h.peek() : 0;
}
